  public String toString() { return "ref " + elemType; }
}

/** The function type: (T1, T2, ... -> Tr). */
class FunType implements Type {
  private Type[] paramTypes;
  private Type returnType;
  FunType(Type[] p, Type r) { paramTypes = p; returnType = r; }
  public Type[] paramTypes() { return paramTypes; }
  public Type returnType() { return returnType; }
  public boolean equals(Object o) {
    if (!(o instanceof FunType)) return false;
    FunType ft = (FunType) o;
    if (paramTypes.length != ft.paramTypes.length) return false;
    for (int i = 0; i < paramTypes.length; i++) {
      if (!paramTypes[i].equals(ft.paramTypes[i])) return false;
    }
    return returnType.equals(ft.returnType);
