/** Parser for Typed Jam (Assignment 5) */

import java.io.*;
import java.util.*;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

/** Token class for the colon separator in type annotations. */
class Colon implements Token {
  public static final Colon ONLY = new Colon();
  private Colon() {}
  public String toString() { return ":"; }
}

/** Token class for type keywords (int, bool, unit, list). */
class TypeToken implements Token {
  private String name;
  TypeToken(String n) { name = n; }
  public String name() { return name; }
  public String toString() { return name; }
}

/** Extended Lexer that handles ':' as a Colon token and adds type keywords. */
class TypedLexer extends Lexer {
  static final TypeToken INT_TYPE = new TypeToken("int");
  static final TypeToken BOOL_TYPE = new TypeToken("bool");
  static final TypeToken UNIT_TYPE = new TypeToken("unit");
  static final TypeToken LIST_TYPE = new TypeToken("list");

  TypedLexer(Reader inputStream) {
    super(inputStream);
    wordTable.put("int", INT_TYPE);
    wordTable.put("bool", BOOL_TYPE);
    wordTable.put("unit", UNIT_TYPE);
    wordTable.put("list", LIST_TYPE);
  }

  @Override
  public Token readToken() {
    try {
      return super.readToken();
    } catch (ParseException e) {
      String msg = e.getMessage();
      if (msg != null && msg.contains("':' is not a legal token")) {
        return Colon.ONLY;
      }
      throw e;
    }
  }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; initParser(); }

  Parser(Reader inputStream) { this(new TypedLexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    }
    finally {
      try { in.rdr.close(); }
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);
    prog.accept(CheckVisitor.INITIAL);
    return prog;
  }

  /** Parses an expression.
    *   Exp ::= if Exp then Exp else Exp
    *         | let Def+ in Exp
    *         | map TypedIdList to Exp
    *         | { PropStatementList }
    *         | Term { Binop Exp }
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken();
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
      next = in.peek();
    }
    return exp;
  }

  /** Parses a term.
    *   Term ::= Unop Term
    *          | Factor { ( ExpList ) }
    *          | Prim ( ExpList )
    *          | Empty
    *          | Int | Bool
    */
  private AST parseTerm(Token token) {

    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op,"unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    // Typed empty: empty : Type
    if (token == EmptyConstant.ONLY) {
      Token colon = in.readToken();
      if (!(colon instanceof Colon)) error(colon, "':' after 'empty'");
      Type type = parseType();
      return new TypedEmpty(type);
    }

    // Int and Bool constants
    if (token instanceof IntConstant) return (IntConstant) token;
    if (token instanceof BoolConstant) return (BoolConstant) token;

    // Valid Prim: must be followed by ( args )
    if (isValidPrim(token)) {
      Token next = in.readToken();
      if (next != LeftParen.ONLY) error(next, "'(' after primitive '" + token + "'");
      AST[] args = parseArgs();
      return new App((PrimFun) token, args);
    }

    // Eliminated primitives: error
    if (token instanceof PrimFun) {
      throw new ParseException("Primitive '" + token + "' is not supported in Typed Jam");
    }

    // Factor: Variable or (Exp), possibly followed by ( args )
    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();
      AST[] exps = parseArgs();
      return new App(factor, exps);
    }
    return factor;
  }

  /** Returns true if the token is a valid primitive in Typed Jam.
    * Prim ::= empty? | cons? | cons | first | rest */
  private boolean isValidPrim(Token t) {
    return t == EmptyPPrim.ONLY || t == ConsPPrim.ONLY ||
           t == ConsPrim.ONLY || t == FirstPrim.ONLY || t == RestPrim.ONLY;
  }

  /** Parses a factor: ( Exp ) | Id */
  private AST parseFactor(Token token) {
    if (token == LeftParen.ONLY) {
      AST exp = parseExp();
      token = in.readToken();
      if (token != RightParen.ONLY) error(token,"')'");
      return exp;
    }
    if (! (token instanceof Variable))
      error(token,"variable, constant, or '('");
    return (Term) token;
  }

  /** Parses 'if Exp then Exp else Exp' given that 'if' has already been read. */
  private AST parseIf() {
    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1,"'then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2,"'else'");
    AST alt = parseExp();
    return new If(test,conseq,alt);
  }

  /** Parses 'let Def+ in Exp' given that 'let' has already been read. */
  private AST parseLet() {
    Def[] defs = parseDefs(false);
    AST body = parseExp();
    return new Let(defs,body);
  }

  /** Parses 'map TypedIdList to Exp' given that 'map' has already been read.
    * TypedIdList ::= { PropTypedIdList }
    * PropTypedIdList ::= TypedId | TypedId , PropTypedIdList
    * TypedId ::= Id : Type
    */
  private AST parseMap() {
    LinkedList<Variable> vars = new LinkedList<Variable>();
    LinkedList<Type> types = new LinkedList<Type>();
    Token t = in.readToken();
    if (t == Lexer.TO) {
      AST body = parseExp();
      return new Map(new Variable[0], new Type[0], body);
    }
    do {
      if (! (t instanceof Variable)) error(t,"variable");
      vars.addLast((Variable) t);
      Token colon = in.readToken();
      if (!(colon instanceof Colon)) error(colon, "':' in typed parameter");
      types.addLast(parseType());
      t = in.readToken();
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "'to' or ','");
      t = in.readToken();
    } while (true);
    AST body = parseExp();
    return new Map(
      vars.toArray(new Variable[0]),
      types.toArray(new Type[0]),
      body
    );
  }

  /** Parses '<exp-list> <delim>' where
    *  <exp-list>      ::= <empty> | <prop-exp-list>
    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list>
    */
  private AST[] parseExps(Token separator, Token delim) {
    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken();
      return new AST[0];
    }

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next,"'" + separator + "' or '" + delim + "'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY,RightParen.ONLY); }

  /** Parses a proper list of typed definitions.
    *   Def ::= TypedId := Exp ;
    *   TypedId ::= Id : Type
    * Consumes 'in' following the definition list. */
  private Def[] parseDefs(boolean forceMap) {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);
      if (forceMap && (! (d.rhs() instanceof Map)))
        throw new ParseException("right hand side of definition '" + d + "' is not a map expression");
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses TypedId := Exp ; given that the first token (variable name) has been read. */
  private Def parseDef(Token var) {
    if (! (var instanceof Variable)) error(var, "variable");

    Token colon = in.readToken();
    if (!(colon instanceof Colon)) error(colon, "':' in typed definition");
    Type type = parseType();

    Token key = in.readToken();
    if (key != Lexer.BIND) error(key,"':='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi,"';'");
    return new Def((Variable) var, type, exp);
  }

  /** Parses a type expression.
    * Type ::= unit | int | bool | list Type | ref Type | (TypeList -> Type)
    * TypeList ::= { PropTypeList }
    * PropTypeList ::= Type | Type , PropTypeList
    */
  private Type parseType() {
    Token t = in.readToken();

    // Type keywords: int, bool, unit, list
    if (t == TypedLexer.INT_TYPE) return IntType.ONLY;
    if (t == TypedLexer.BOOL_TYPE) return BoolType.ONLY;
    if (t == TypedLexer.UNIT_TYPE) return UnitType.ONLY;
    if (t == TypedLexer.LIST_TYPE) return new ListType(parseType());

    // ref Type
    if (t == Lexer.REF) return new RefType(parseType());

    // (TypeList -> Type)
    if (t == LeftParen.ONLY) {
      LinkedList<Type> paramTypes = new LinkedList<Type>();
      // Check if type list is empty (-> immediately follows)
      if (in.peek() != Lexer.MINUS) {
        paramTypes.addLast(parseType());
        while (in.peek() == Comma.ONLY) {
          in.readToken(); // consume comma
          paramTypes.addLast(parseType());
        }
      }
      // Expect ->
      Token arrow1 = in.readToken();
      if (arrow1 != Lexer.MINUS) error(arrow1, "'->'");
      Token arrow2 = in.readToken();
      if (arrow2 != Lexer.GREATER_THAN) error(arrow2, "'>' in '->'");
      Type returnType = parseType();
      Token closeParen = in.readToken();
      if (closeParen != RightParen.ONLY) error(closeParen, "')'");
      return new FunType(paramTypes.toArray(new Type[0]), returnType);
    }

    error(t, "type");
    return null; // unreachable
  }

  private AST error(Token found, String expected) {
    throw new ParseException("Token '" + found + "' appears where " + expected + " was expected");
  }

  public static void main(String[] args) throws IOException {
    if (args.length == 0) return;
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
  }
}

/** Type checker for Typed Jam (Assignment 5). */

/** Exception class for type errors. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Type checker that walks the AST and verifies type consistency.
  * Uses a type environment mapping variables to their declared types. */
class TypeChecker {

  /** Binding from Variable to Type for the type environment. */
  static class TypeBinding implements WithVariable {
    private Variable var;
    private Type type;
    TypeBinding(Variable v, Type t) { var = v; type = t; }
    public Variable var() { return var; }
    public Type type() { return type; }
  }

  /** The type environment. */
  private PureList<TypeBinding> env;

  /** Creates a TypeChecker with the given type environment. */
  TypeChecker(PureList<TypeBinding> e) { env = e; }

  /** Creates a TypeChecker with an empty environment. */
  TypeChecker() { this(new Empty<TypeBinding>()); }

  /** Type-checks the given AST and returns its type. Throws TypeException on error. */
  Type check(AST ast) {
    if (ast instanceof IntConstant) return IntType.ONLY;
    if (ast instanceof BoolConstant) return BoolType.ONLY;
    if (ast instanceof TypedEmpty) return new ListType(((TypedEmpty) ast).type());
    if (ast instanceof EmptyConstant) throw new TypeException("Untyped empty constant");
    if (ast instanceof Variable) return checkVariable((Variable) ast);
    if (ast instanceof PrimFun) throw new TypeException("Primitive '" + ast + "' used as value");
    if (ast instanceof UnOpApp) return checkUnOpApp((UnOpApp) ast);
    if (ast instanceof BinOpApp) return checkBinOpApp((BinOpApp) ast);
    if (ast instanceof App) return checkApp((App) ast);
    if (ast instanceof Map) return checkMap((Map) ast);
    if (ast instanceof If) return checkIf((If) ast);
    if (ast instanceof Let) return checkLet((Let) ast);
    if (ast instanceof Block) return checkBlock((Block) ast);
    throw new TypeException("Unknown AST node: " + ast);
  }

  /** Looks up a variable in the type environment. */
  private Type checkVariable(Variable v) {
    TypeBinding match = env.accept(new LookupVisitor<TypeBinding>(v));
    if (match == null) throw new TypeException("variable " + v + " is unbound");
    return match.type();
  }

  /** Type-checks a unary operator application. */
  private Type checkUnOpApp(UnOpApp u) {
    Type argType = check(u.arg());
    return u.rator().accept(new UnOpTypeChecker(argType));
  }

  /** Type-checks a binary operator application. */
  private Type checkBinOpApp(BinOpApp b) {
    Type arg1Type = check(b.arg1());
    Type arg2Type = check(b.arg2());
    return b.rator().accept(new BinOpTypeChecker(arg1Type, arg2Type));
  }

  /** Type-checks a function application (including primitive applications). */
  private Type checkApp(App a) {
    AST rator = a.rator();
    AST[] args = a.args();

    // Handle primitive function applications
    if (rator instanceof PrimFun) {
      return checkPrimApp((PrimFun) rator, args);
    }

    // Handle user-defined function applications
    Type ratorType = check(rator);
    if (!(ratorType instanceof FunType)) {
      throw new TypeException(rator + " has type " + ratorType + " which is not a function type");
    }
    FunType funType = (FunType) ratorType;
    Type[] paramTypes = funType.paramTypes();
    if (paramTypes.length != args.length) {
      throw new TypeException("Function expects " + paramTypes.length + " arguments but got " + args.length);
    }
    for (int i = 0; i < args.length; i++) {
      Type argType = check(args[i]);
      if (!argType.equals(paramTypes[i])) {
        throw new TypeException("Argument " + (i + 1) + " has type " + argType +
            " but " + paramTypes[i] + " expected");
      }
    }
    return funType.returnType();
  }

  /** Type-checks a primitive function application.
    * Handles polymorphic primitives (cons, first, rest, empty?, cons?). */
  private Type checkPrimApp(PrimFun pf, AST[] args) {

    // cons : 'a, list 'a -> list 'a
    if (pf instanceof ConsPrim) {
      if (args.length != 2) throw new TypeException("cons requires 2 arguments");
      Type firstType = check(args[0]);
      Type restType = check(args[1]);
      if (!(restType instanceof ListType)) {
        throw new TypeException("Second argument to cons must be a list, got " + restType);
      }
      Type elemType = ((ListType) restType).elemType();
      if (!firstType.equals(elemType)) {
        throw new TypeException("First argument to cons has type " + firstType +
            " but list element type is " + elemType);
      }
      return restType;
    }

    // first : list 'a -> 'a
    if (pf instanceof FirstPrim) {
      if (args.length != 1) throw new TypeException("first requires 1 argument");
      Type argType = check(args[0]);
      if (!(argType instanceof ListType)) {
        throw new TypeException("Argument to first must be a list, got " + argType);
      }
      return ((ListType) argType).elemType();
    }

    // rest : list 'a -> list 'a
    if (pf instanceof RestPrim) {
      if (args.length != 1) throw new TypeException("rest requires 1 argument");
      Type argType = check(args[0]);
      if (!(argType instanceof ListType)) {
        throw new TypeException("Argument to rest must be a list, got " + argType);
      }
      return argType;
    }

    // empty? : list 'a -> bool
    if (pf instanceof EmptyPPrim) {
      if (args.length != 1) throw new TypeException("empty? requires 1 argument");
      Type argType = check(args[0]);
      if (!(argType instanceof ListType)) {
        throw new TypeException("Argument to empty? must be a list, got " + argType);
      }
      return BoolType.ONLY;
    }

    // cons? : list 'a -> bool
    if (pf instanceof ConsPPrim) {
      if (args.length != 1) throw new TypeException("cons? requires 1 argument");
      Type argType = check(args[0]);
      if (!(argType instanceof ListType)) {
        throw new TypeException("Argument to cons? must be a list, got " + argType);
      }
      return BoolType.ONLY;
    }

    throw new TypeException("Unsupported primitive: " + pf);
  }

  /** Type-checks a map (lambda) expression. Returns a FunType. */
  private Type checkMap(Map m) {
    Variable[] vars = m.vars();
    Type[] types = m.types();
    PureList<TypeBinding> newEnv = env;
    for (int i = vars.length - 1; i >= 0; i--) {
      newEnv = newEnv.cons(new TypeBinding(vars[i], types[i]));
    }
    TypeChecker newTC = new TypeChecker(newEnv);
    Type bodyType = newTC.check(m.body());
    return new FunType(types.clone(), bodyType);
  }

  /** Type-checks an if-then-else expression. */
  private Type checkIf(If i) {
    Type testType = check(i.test());
    if (!testType.equals(BoolType.ONLY)) {
      throw new TypeException("If test must be bool, got " + testType);
    }
    Type conseqType = check(i.conseq());
    Type altType = check(i.alt());
    if (!conseqType.equals(altType)) {
      throw new TypeException("If branches have different types: " + conseqType + " and " + altType);
    }
    return conseqType;
  }

  /** Type-checks a let expression with recursive definitions. */
  private Type checkLet(Let l) {
    Def[] defs = l.defs();
    Variable[] vars = l.vars();

    // Build extended environment with declared types (for recursive defs)
    PureList<TypeBinding> newEnv = env;
    for (int i = vars.length - 1; i >= 0; i--) {
      newEnv = newEnv.cons(new TypeBinding(vars[i], defs[i].type()));
    }
    TypeChecker newTC = new TypeChecker(newEnv);

    // Check each RHS type matches declared type
    for (int i = 0; i < defs.length; i++) {
      Type rhsType = newTC.check(defs[i].rhs());
      if (!rhsType.equals(defs[i].type())) {
        throw new TypeException("Definition of " + vars[i] + " declared type " +
            defs[i].type() + " but RHS has type " + rhsType);
      }
    }
    return newTC.check(l.body());
  }

  /** Type-checks a block expression. Returns the type of the last expression. */
  private Type checkBlock(Block b) {
    AST[] exps = b.exps();
    Type result = null;
    for (AST exp : exps) {
      result = check(exp);
    }
    return result;
  }

  /** Visitor for type-checking unary operators. */
  class UnOpTypeChecker implements UnOpVisitor<Type> {
    private Type argType;
    UnOpTypeChecker(Type t) { argType = t; }

    public Type forUnOpPlus() {
      if (!argType.equals(IntType.ONLY))
        throw new TypeException("Unary '+' requires int, got " + argType);
      return IntType.ONLY;
    }
    public Type forUnOpMinus() {
      if (!argType.equals(IntType.ONLY))
        throw new TypeException("Unary '-' requires int, got " + argType);
      return IntType.ONLY;
    }
    public Type forOpTilde() {
      if (!argType.equals(BoolType.ONLY))
        throw new TypeException("'~' requires bool, got " + argType);
      return BoolType.ONLY;
    }
    public Type forOpBang() {
      if (!(argType instanceof RefType))
        throw new TypeException("'!' requires ref type, got " + argType);
      return ((RefType) argType).elemType();
    }
    public Type forOpRef() {
      return new RefType(argType);
    }
  }

  /** Visitor for type-checking binary operators. */
  class BinOpTypeChecker implements BinOpVisitor<Type> {
    private Type arg1Type, arg2Type;
    BinOpTypeChecker(Type t1, Type t2) { arg1Type = t1; arg2Type = t2; }

    private void requireBothInt(String op) {
      if (!arg1Type.equals(IntType.ONLY))
        throw new TypeException("'" + op + "' requires int, got " + arg1Type);
      if (!arg2Type.equals(IntType.ONLY))
        throw new TypeException("'" + op + "' requires int, got " + arg2Type);
    }
    private void requireBothBool(String op) {
      if (!arg1Type.equals(BoolType.ONLY))
        throw new TypeException("'" + op + "' requires bool, got " + arg1Type);
      if (!arg2Type.equals(BoolType.ONLY))
        throw new TypeException("'" + op + "' requires bool, got " + arg2Type);
    }

    public Type forBinOpPlus() { requireBothInt("+"); return IntType.ONLY; }
    public Type forBinOpMinus() { requireBothInt("-"); return IntType.ONLY; }
    public Type forOpTimes() { requireBothInt("*"); return IntType.ONLY; }
    public Type forOpDivide() { requireBothInt("/"); return IntType.ONLY; }
    public Type forOpLessThan() { requireBothInt("<"); return BoolType.ONLY; }
    public Type forOpGreaterThan() { requireBothInt(">"); return BoolType.ONLY; }
    public Type forOpLessThanEquals() { requireBothInt("<="); return BoolType.ONLY; }
    public Type forOpGreaterThanEquals() { requireBothInt(">="); return BoolType.ONLY; }
    public Type forOpAnd() { requireBothBool("&"); return BoolType.ONLY; }
    public Type forOpOr() { requireBothBool("|"); return BoolType.ONLY; }

    public Type forOpEquals() {
      if (!arg1Type.equals(arg2Type))
        throw new TypeException("'=' requires same types, got " + arg1Type + " and " + arg2Type);
      return BoolType.ONLY;
    }
    public Type forOpNotEquals() {
      if (!arg1Type.equals(arg2Type))
        throw new TypeException("'!=' requires same types, got " + arg1Type + " and " + arg2Type);
      return BoolType.ONLY;
    }
    public Type forOpGets() {
      if (!(arg1Type instanceof RefType))
        throw new TypeException("'<-' left side must be ref type, got " + arg1Type);
      Type elemType = ((RefType) arg1Type).elemType();
      if (!arg2Type.equals(elemType))
        throw new TypeException("'<-' right side has type " + arg2Type +
            " but ref element type is " + elemType);
      return UnitType.ONLY;
    }
  }
}

