import junit.framework.TestCase;
import java.io.*;

/** Agent tests for Typed Jam - covers edge cases beyond public tests. */
public class Assign5AgentTest extends TestCase {

  public Assign5AgentTest(String name) { super(name); }

  private void eagerCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("eager " + name, answer, interp.eagerEval().toString());
  }

  private void lazyCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("lazy " + name, answer, interp.lazyEval().toString());
  }

  private void allCheck(String name, String answer, String program) {
    eagerCheck(name, answer, program);
    lazyCheck(name, answer, program);
  }

  // --- Basic arithmetic ---
  public void testSimpleAdd() {
    allCheck("simpleAdd", "5", "2 + 3");
  }

  public void testSimpleMul() {
    allCheck("simpleMul", "12", "3 * 4");
  }

  public void testNegation() {
    allCheck("negation", "-5", "- 5");
  }

  public void testBoolNot() {
    allCheck("boolNot", "false", "~ true");
  }

  // --- Type checking: correct programs ---
  public void testLetSimple() {
    allCheck("letSimple", "10",
        "let x: int := 5; in x + x");
  }

  public void testLetBool() {
    allCheck("letBool", "true",
        "let b: bool := true; in b & true");
  }

  public void testMapApply() {
    allCheck("mapApply", "7",
        "let f: (int -> int) := map x: int to x + 1; in f(6)");
  }

  public void testMapTwoArgs() {
    allCheck("mapTwoArgs", "15",
        "let add: (int, int -> int) := map x: int, y: int to x + y; in add(7, 8)");
  }

  public void testEmptyInt() {
    allCheck("emptyInt", "()", "empty: int");
  }

  public void testConsList() {
    allCheck("consList", "(1 2 3)",
        "cons(1, cons(2, cons(3, empty: int)))");
  }

  public void testFirstCons() {
    allCheck("firstCons", "42",
        "first(cons(42, empty: int))");
  }

  public void testRestCons() {
    allCheck("restCons", "(2 3)",
        "rest(cons(1, cons(2, cons(3, empty: int))))");
  }

  public void testEmptyPred() {
    allCheck("emptyPred", "true",
        "empty?(empty: int)");
  }

  public void testConsPred() {
    allCheck("consPred", "true",
        "cons?(cons(1, empty: int))");
  }

  public void testEmptyPredFalse() {
    allCheck("emptyPredFalse", "false",
        "empty?(cons(1, empty: int))");
  }

  // --- If-then-else ---
  public void testIfTrue() {
    allCheck("ifTrue", "1", "if true then 1 else 2");
  }

  public void testIfFalse() {
    allCheck("ifFalse", "2", "if false then 1 else 2");
  }

  // --- Ref cells ---
  public void testRefBasic() {
    allCheck("refBasic", "5",
        "let r: ref int := ref 5; in !r");
  }

  public void testRefAssign() {
    allCheck("refAssign", "10",
        "let r: ref int := ref 5; in { r <- 10; !r }");
  }

  public void testRefAssignUnit() {
    allCheck("refAssignUnit", "unit",
        "let r: ref int := ref 5; in r <- 10");
  }

  // --- Blocks ---
  public void testBlockSingle() {
    allCheck("blockSingle", "42", "{42}");
  }

  public void testBlockMultiple() {
    allCheck("blockMultiple", "3", "{1; 2; 3}");
  }

  // --- Type errors ---
  public void testTypeErrorAddBool() {
    try {
      allCheck("typeErrorAddBool", "err", "1 + true");
      fail("Expected TypeException for 1 + true");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorIfNotBool() {
    try {
      allCheck("typeErrorIfNotBool", "err", "if 5 then 1 else 2");
      fail("Expected TypeException for if 5...");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorIfBranchMismatch() {
    try {
      allCheck("typeErrorIfMismatch", "err", "if true then 1 else true");
      fail("Expected TypeException for mismatched if branches");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorBangNonRef() {
    try {
      allCheck("typeErrorBangNonRef", "err", "! 5");
      fail("Expected TypeException for ! 5");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorGetsNonRef() {
    try {
      allCheck("typeErrorGetsNonRef", "err", "5 <- 3");
      fail("Expected TypeException for 5 <- 3");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorLetMismatch() {
    try {
      allCheck("typeErrorLetMismatch", "err",
          "let x: bool := 5; in x");
      fail("Expected TypeException for int assigned to bool");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorConsTypeMismatch() {
    try {
      allCheck("typeErrorConsMismatch", "err",
          "cons(true, cons(1, empty: int))");
      fail("Expected TypeException for cons type mismatch");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorFirstNonList() {
    try {
      allCheck("typeErrorFirstNonList", "err", "first(5)");
      fail("Expected TypeException for first(5)");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorEqualsMismatch() {
    try {
      allCheck("typeErrorEqualsMismatch", "err", "1 = true");
      fail("Expected TypeException for 1 = true");
    } catch (TypeException e) { /* expected */ }
  }

  public void testTypeErrorWrongArgCount() {
    try {
      allCheck("typeErrorWrongArgCount", "err",
          "let f: (int -> int) := map x: int to x; in f(1, 2)");
      fail("Expected TypeException for wrong arg count");
    } catch (TypeException e) { /* expected */ }
  }

  // --- Parse errors for eliminated prims ---
  public void testEliminatedArity() {
    try {
      allCheck("eliminatedArity", "err",
          "arity(map x: int to x)");
      fail("Expected ParseException for arity");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedNumberP() {
    try {
      allCheck("eliminatedNumberP", "err", "number?(5)");
      fail("Expected ParseException for number?");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedFunctionP() {
    try {
      allCheck("eliminatedFunctionP", "err",
          "function?(map x: int to x)");
      fail("Expected ParseException for function?");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedListP() {
    try {
      allCheck("eliminatedListP", "err", "list?(empty: int)");
      fail("Expected ParseException for list?");
    } catch (ParseException e) { /* expected */ }
  }

  public void testEliminatedRefP() {
    try {
      allCheck("eliminatedRefP", "err", "ref?(ref 5)");
      fail("Expected ParseException for ref?");
    } catch (ParseException e) { /* expected */ }
  }

  // --- Complex typed programs ---
  public void testRecursiveFunction() {
    allCheck("recursive", "120",
        "let fact: (int -> int) := map n: int to if n = 0 then 1 else n * fact(n - 1); in fact(5)");
  }

  public void testZeroArgMap() {
    allCheck("zeroArgMap", "42",
        "let f: ( -> int) := map to 42; in f()");
  }

  public void testHigherOrderFunction() {
    allCheck("higherOrder", "10",
        "let apply: ((int -> int), int -> int) := map f: (int -> int), x: int to f(x); " +
        "double: (int -> int) := map x: int to x * 2; in apply(double, 5)");
  }

  public void testNestedLet() {
    allCheck("nestedLet", "15",
        "let x: int := 5; in let y: int := x + 10; in y");
  }

  public void testListOfBools() {
    allCheck("listOfBools", "(true false)",
        "cons(true, cons(false, empty: bool))");
  }

  // --- Comparison operators ---
  public void testLessThan() {
    allCheck("lessThan", "true", "3 < 5");
  }

  public void testGreaterThan() {
    allCheck("greaterThan", "false", "3 > 5");
  }

  public void testEqualsInt() {
    allCheck("equalsInt", "true", "5 = 5");
  }

  public void testNotEquals() {
    allCheck("notEquals", "true", "3 != 5");
  }

  // --- Short-circuit boolean ---
  public void testAndShortCircuit() {
    allCheck("andShortCircuit", "false", "false & true");
  }

  public void testOrShortCircuit() {
    allCheck("orShortCircuit", "true", "true | false");
  }

  // --- Complex type annotations ---
  public void testRefList() {
    allCheck("refList", "(1 2)",
        "let r: ref list int := ref cons(1, cons(2, empty: int)); in !r");
  }

  public void testNestedListType() {
    allCheck("nestedListType", "((1 2) (3 4))",
        "let l1: list int := cons(1, cons(2, empty: int)); " +
        "l2: list int := cons(3, cons(4, empty: int)); " +
        "in cons(l1, cons(l2, empty: list int))");
  }
}
